defaultModel:
{{
  (function() {
    function decode(data) {
      if (!data) return null;
      try { return atob(data); } catch(e) { return data; }
    }
    function parseCSV(text) {
      if (!text) return [];
      var lines = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n').filter(function(l) { return l.trim(); });
      var headers = lines[0].split(',');
      return lines.slice(1).map(function(line) {
        var values = line.split(',');
        return headers.reduce(function(obj, h, i) {
          obj[h.trim()] = values[i] ? values[i].trim() : '';
          return obj;
        }, {});
      });
    }
    function parseJSON(data) {
      if (!data) return {};
      try { return JSON.parse(decode(data)); } catch(e) { return {}; }
    }
    return {
      "identity_summary":     parseCSV(decode(Identity_Summary.data.fileData)),
      "identities":           parseCSV(decode(Identities.data.fileData)),
      "zendata_telemetry":    parseJSON(Zendata_Telemetry.data.fileData),
      "sailpoint_identities": parseJSON(Sailpoint_Identities.data.fileData),
      "events":               parseCSV(decode(Events.data.fileData))
    };
  })()
}}
